+/**
+ * Notification log model — records sent notifications for history tracking.
+ *
+ * Each log entry captures who received the notification, through what channel,
+ * what type it was, when it was sent, and whether delivery succeeded.
+ */
+
+import type { NotificationChannel, NotificationPriority, NotificationType } from './notification.js';
+
+/** Delivery status of a logged notification. */
+export type DeliveryStatus = 'sent' | 'failed' | 'suppressed';
+
+/** A persisted notification log entry. */
+export interface NotificationLog {
+  /** Auto-generated ID (nlog-0001, nlog-0002, ...). */
+  id: string;
+  /** The notification ID this log corresponds to (if any). */
+  notificationId: string;
+  /** Recipient identifier (email address, user ID, webhook URL, etc.). */
+  recipient: string;
+  /** Delivery channel used. */
+  channel: NotificationChannel;
+  /** What triggered this notification. */
+  notificationType: NotificationType;
+  /** Delivery priority. */
+  priority: NotificationPriority;
+  /** Delivery outcome. */
+  status: DeliveryStatus;
+  /** Error message if delivery failed. */
+  error?: string;
+  /** When the notification was sent/attempted. */
+  timestamp: Date;
+}
+
+/** Filters for querying notification history. */
+export interface NotificationHistoryQuery {
+  /** Filter by recipient. */
+  recipient?: string;
+  /** Filter by notification type. */
+  notificationType?: NotificationType;
+  /** Filter by channel. */
+  channel?: NotificationChannel;
+  /** Filter by delivery status. */
+  status?: DeliveryStatus;
+  /** Start of date range (inclusive). */
+  from?: Date;
+  /** End of date range (inclusive). */
+  to?: Date;
+}

