import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationPriority, NotificationType } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    return {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      notificationType: record['notificationType'] as NotificationType,
      priority: record['priority'] as NotificationPriority,
      status: record['status'] as DeliveryStatus,
      error: record['error'] as string | undefined,
      timestamp: new Date(record['timestamp'] as string),
    };
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    return {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      notificationType: entity.notificationType,
      priority: entity.priority,
      status: entity.status,
      error: entity.error,
      timestamp: entity.timestamp.toISOString(),
    };
  }

  /** Find all logs for a given recipient. */
  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  /** Find all logs for a given notification type. */
  findByType(notificationType: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.notificationType === notificationType);
  }

  /** Find all logs for a given channel. */
  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }
}

/**
 * Notification history service — logs sent notifications and provides
 * query capabilities for notification history.
 *
 * Integrates with NotificationService by subscribing to notification:send
 * events on the EventBus and recording each dispatched notification.
 *
 * Depends on:
 * - EventBus (to listen for notification:send events)
 * - NotificationLogRepository (data access)
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSendEvent } from '../events/event-types.js';
import type {
  NotificationLog,
  NotificationHistoryQuery,
} from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private repository: NotificationLogRepository,
  ) {
    this.registerEventHandlers();
  }

  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSendEvent>('notification:send', (event) => {
      this.logNotification(event);
    });
  }

  private logNotification(event: NotificationSendEvent): void {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.payload.notificationId ?? '',
      recipient: event.payload.recipient,
      channel: event.payload.channel,
      notificationType: event.payload.notificationType,
      priority: event.payload.priority ?? 'normal',
      status: 'sent',
      timestamp: event.timestamp,
    };

    this.repository.save(log);
    this.logger.info(
      `Logged notification ${log.id}: ${log.notificationType} to ${log.recipient} via ${log.channel}`,
    );
  }

  /** Record a failed delivery attempt. */
  logFailure(
    notificationId: string,
    recipient: string,
    channel: NotificationLog['channel'],
    notificationType: NotificationLog['notificationType'],
    priority: NotificationLog['priority'],
    error: string,
  ): NotificationLog {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId,
      recipient,
      channel,
      notificationType,
      priority,
      status: 'failed',
      error,
      timestamp: new Date(),
    };

    this.repository.save(log);
    this.logger.warn(`Logged failure ${log.id}: ${error}`);
    return log;
  }

  /** Record a suppressed notification (e.g., by user preferences). */
  logSuppressed(
    recipient: string,
    channel: NotificationLog['channel'],
    notificationType: NotificationLog['notificationType'],
    priority: NotificationLog['priority'],
  ): NotificationLog {
    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: '',
      recipient,
      channel,
      notificationType,
      priority,
      status: 'suppressed',
      timestamp: new Date(),
    };

    this.repository.save(log);
    this.logger.info(`Logged suppression ${log.id}: ${notificationType} to ${recipient}`);
    return log;
  }

  /**
   * Query notification history with optional filters.
   * All filters are ANDed together.
   */
  query(filters: NotificationHistoryQuery): NotificationLog[] {
    return this.repository.findAll((log) => {
      if (filters.recipient && log.recipient !== filters.recipient) return false;
      if (filters.notificationType && log.notificationType !== filters.notificationType) return false;
      if (filters.channel && log.channel !== filters.channel) return false;
      if (filters.status && log.status !== filters.status) return false;
      if (filters.from && log.timestamp < filters.from) return false;
      if (filters.to && log.timestamp > filters.to) return false;
      return true;
    });
  }

  /** Get all log entries for a specific recipient. */
  getHistoryForRecipient(recipient: string): NotificationLog[] {
    return this.repository.findByRecipient(recipient);
  }

  /** Get all log entries for a specific notification type. */
  getHistoryByType(notificationType: NotificationLog['notificationType']): NotificationLog[] {
    return this.repository.findByType(notificationType);
  }

  /** Get all log entries within a date range. */
  getHistoryByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.query({ from, to });
  }

  /** Get a single log entry by ID. */
  getLogEntry(id: string): NotificationLog | undefined {
    return this.repository.findById(id);
  }

  /** Get all log entries. */
  getAllHistory(): NotificationLog[] {
    return this.repository.findAll();
  }

  /** Get the total count of log entries. */
  getLogCount(): number {
    return this.repository.count();
  }
}

