} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
    ...overrides,
  };
}

function makeStatusChangedEvent(overrides?: Partial<OrderStatusChangedEvent>): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let eventBus: EventBus;
  let db: Database;
  let logRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    eventBus = new EventBus();
    db = new Database();
    logRepo = new NotificationLogRepository(db);
    notificationService = new NotificationService(eventBus);
    historyService = new NotificationHistoryService(eventBus, logRepo);
    notificationService.setHistoryService(historyService);
    emailAdapter = new EmailAdapter(eventBus);
    notificationService.registerAdapter(emailAdapter);
    resetLogIdCounter();
    resetNotificationIdCounter();
  });

  describe('automatic logging on notification dispatch', () => {
    it('should log a notification when order:created triggers a notification', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAllHistory();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.notificationType).toBe('order_confirmation');
      expect(logs[0]!.status).toBe('sent');
      expect(logs[0]!.priority).toBe('normal');
    });

    it('should log a notification when order:status-changed triggers a notification', async () => {
      await eventBus.emit(makeStatusChangedEvent());

      const logs = historyService.getAllHistory();
      expect(logs).toHaveLength(1);
      expect(logs[0]!.notificationType).toBe('order_status_update');
      expect(logs[0]!.status).toBe('sent');
    });

    it('should capture the notification ID from the dispatched notification', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const logs = historyService.getAllHistory();
      expect(logs[0]!.notificationId).toBe('notif-0001');
    });

    it('should log multiple notifications with sequential IDs', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const logs = historyService.getAllHistory();
      expect(logs).toHaveLength(2);
      expect(logs[0]!.id).toBe('nlog-0001');
      expect(logs[1]!.id).toBe('nlog-0002');
    });

    it('should record the timestamp from the notification event', async () => {
      const timestamp = new Date('2026-01-15T10:30:00Z');
      await eventBus.emit(makeOrderCreatedEvent({ timestamp }));

      const logs = historyService.getAllHistory();
      expect(logs[0]!.timestamp).toEqual(timestamp);
    });
  });

  describe('manual logging', () => {
    it('should log a failed delivery', () => {
      const log = historyService.logFailure(
        'notif-0001',
        'alice@example.com',
        'email',
        'order_confirmation',
        'normal',
        'SMTP connection timeout',
      );

      expect(log.status).toBe('failed');
      expect(log.error).toBe('SMTP connection timeout');
      expect(log.notificationId).toBe('notif-0001');
      expect(historyService.getLogCount()).toBe(1);
    });

    it('should log a suppressed notification', () => {
      const log = historyService.logSuppressed(
        'alice@example.com',
        'email',
        'order_confirmation',
        'normal',
      );

      expect(log.status).toBe('suppressed');
      expect(log.notificationId).toBe('');
      expect(historyService.getLogCount()).toBe(1);
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const aliceLogs = historyService.getHistoryForRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]!.notificationType).toBe('order_confirmation');

      const bobLogs = historyService.getHistoryForRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());

      const confirmations = historyService.getHistoryByType('order_confirmation');
      expect(confirmations).toHaveLength(1);
      expect(confirmations[0]!.recipient).toBe('alice@example.com');

      const statusUpdates = historyService.getHistoryByType('order_status_update');
      expect(statusUpdates).toHaveLength(1);
    });
  });

  describe('query by date range', () => {
    it('should return logs within a date range', async () => {
      const early = new Date('2026-01-01T00:00:00Z');
      const late = new Date('2026-06-01T00:00:00Z');

      await eventBus.emit(makeOrderCreatedEvent({ timestamp: early }));
      await eventBus.emit(makeStatusChangedEvent({ timestamp: late }));

      const janLogs = historyService.getHistoryByDateRange(
        new Date('2025-12-01T00:00:00Z'),
        new Date('2026-02-01T00:00:00Z'),
      );
      expect(janLogs).toHaveLength(1);
      expect(janLogs[0]!.notificationType).toBe('order_confirmation');

      const allLogs = historyService.getHistoryByDateRange(
        new Date('2025-01-01T00:00:00Z'),
        new Date('2027-01-01T00:00:00Z'),
      );
      expect(allLogs).toHaveLength(2);
    });
  });

  describe('complex queries', () => {
    it('should filter by multiple criteria', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());
      historyService.logFailure('notif-0003', 'alice@example.com', 'email', 'order_confirmation', 'normal', 'error');

      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'sent',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.notificationType).toBe('order_confirmation');
    });

    it('should filter by channel', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.query({ channel: 'email' });
      expect(emailLogs).toHaveLength(1);

      const webhookLogs = historyService.query({ channel: 'webhook' });
      expect(webhookLogs).toHaveLength(0);
    });

    it('should return empty array when no logs match', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('getLogEntry', () => {
    it('should retrieve a single log entry by ID', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const log = historyService.getLogEntry('nlog-0001');
      expect(log).toBeDefined();
      expect(log!.recipient).toBe('alice@example.com');
    });

    it('should return undefined for non-existent ID', () => {
      const log = historyService.getLogEntry('nlog-9999');
      expect(log).toBeUndefined();
    });
  });

  describe('getLogCount', () => {
    it('should return 0 when no logs exist', () => {
      expect(historyService.getLogCount()).toBe(0);
    });

    it('should return correct count after logging', async () => {
      await eventBus.emit(makeOrderCreatedEvent());
      await eventBus.emit(makeStatusChangedEvent());
      expect(historyService.getLogCount()).toBe(2);
    });
  });
});

